compliant:
[HttpGet]
public IActionResult Search(string query)
{
    var encoded = HtmlEncoder.Default.Encode(query);
    return Content($"<html><body>Results for: {encoded}</body></html>", "text/html");
}

public ActionResult Display(string userInput)
{
    ViewBag.Message = HttpUtility.HtmlEncode(userInput); // Compliant
    return View();
}
